PRAGMA foreign_keys = ON;

CREATE TABLE system_channel (
    channel TEXT PRIMARY KEY,
    default_enabled INTEGER NOT NULL CHECK (default_enabled IN (0, 1))
);

CREATE TABLE workspace (
    workspace_id INTEGER PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE TABLE member (
    workspace_id INTEGER NOT NULL REFERENCES workspace(workspace_id) ON DELETE CASCADE,
    member_id INTEGER NOT NULL,
    display_name TEXT NOT NULL,
    PRIMARY KEY (workspace_id, member_id)
);

CREATE TABLE workspace_channel_override (
    workspace_id INTEGER NOT NULL REFERENCES workspace(workspace_id) ON DELETE CASCADE,
    channel TEXT NOT NULL REFERENCES system_channel(channel) ON DELETE CASCADE,
    enabled INTEGER NOT NULL CHECK (enabled IN (0, 1)),
    PRIMARY KEY (workspace_id, channel)
);

CREATE TABLE member_channel_override (
    workspace_id INTEGER NOT NULL,
    member_id INTEGER NOT NULL,
    channel TEXT NOT NULL REFERENCES system_channel(channel) ON DELETE CASCADE,
    enabled INTEGER NOT NULL CHECK (enabled IN (0, 1)),
    PRIMARY KEY (workspace_id, member_id, channel),
    FOREIGN KEY (workspace_id, member_id) REFERENCES member(workspace_id, member_id) ON DELETE CASCADE
);
